// src/components/ERPChatBot/ERPChatBot.jsx
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { 
  Send, X, Bot, User, Loader2, 
  Sparkles, ChevronRight, Clock,
  BookOpen, DollarSign, Calendar,
  TrendingUp, FileText
} from 'lucide-react';
import './ERPChatBot.css';

const ERPChatBot = ({ studentId, studentName, onClose }) => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState([]);
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef(null);

  // Initial messages
  useEffect(() => {
    const welcomeMessages = [{
      id: 1,
      text: `Hi ${studentName}! 👋 I'm your AI Assistant. I can help you with:\n\n📚 **Courses & Teachers**\n💰 **Fees & Payments**\n📅 **Attendance & Schedule**\n🎯 **Grades & GPA**\n📝 **Assignments & Tasks**\n📊 **Academic Progress**\n\nWhat would you like to know?`,
      sender: 'bot',
      timestamp: new Date().toLocaleTimeString(),
      icon: '🤖'
    }];

    setMessages(welcomeMessages);
    loadSuggestions();
  }, [studentName]);

  const loadSuggestions = () => {
    const defaultSuggestions = [
      { text: "What's my attendance?", icon: "📊" },
      { text: "Show me my fees status", icon: "💰" },
      { text: "Who are my teachers?", icon: "👨‍🏫" },
      { text: "What's my current GPA?", icon: "📈" },
      { text: "Upcoming assignments", icon: "📝" },
      { text: "Today's timetable", icon: "🕒" },
      { text: "Credits completed", icon: "🎯" },
      { text: "Exam schedule", icon: "📅" }
    ];
    setSuggestions(defaultSuggestions);
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = {
      id: Date.now(),
      text: input,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString(),
      icon: '👤'
    };
    
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);
    setIsTyping(true);

    try {
      const response = await axios.post('http://localhost:65000/api/chatbot/ask', {
        question: input,
        studentId: studentId
      }, {
        withCredentials: true,
        headers: {
          'Content-Type': 'application/json'
        }
      });

      setIsTyping(false);

      const botMessage = {
        id: Date.now() + 1,
        text: response.data.answer,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString(),
        icon: '🤖',
        data: response.data
      };
      
      setMessages(prev => [...prev, botMessage]);

    } catch (error) {
      setIsTyping(false);
      console.error("Chatbot error:", error);
      
      const errorMessage = {
        id: Date.now() + 1,
        text: "Sorry, I'm having trouble connecting. Please try again or contact support.",
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString(),
        icon: '🤖',
        isError: true
      };
      
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleQuickQuestion = (question) => {
    setInput(question);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const getIconForCategory = (text) => {
    if (text.includes('attendance')) return '📊';
    if (text.includes('fee') || text.includes('payment')) return '💰';
    if (text.includes('teacher')) return '👨‍🏫';
    if (text.includes('GPA') || text.includes('grade')) return '📈';
    if (text.includes('assignment')) return '📝';
    if (text.includes('timetable') || text.includes('schedule')) return '🕒';
    if (text.includes('credit')) return '🎯';
    if (text.includes('exam')) return '📅';
    return '❓';
  };

  return (
    <div className="erp-chatbot">
      {/* Header */}
      <div className="chatbot-header">
        <div className="header-left">
          <div className="ai-badge">
            <Bot size={18} />
            <span>ERP AI Assistant</span>
          </div>
          <div className="student-info">
            <span className="student-name">{studentName}</span>
            <span className="student-id">• {studentId}</span>
          </div>
        </div>
        <button className="close-btn" onClick={onClose}>
          <X size={20} />
        </button>
      </div>

      {/* Messages Container */}
      <div className="messages-container">
        {messages.map((msg) => (
          <div key={msg.id} className={`message-bubble ${msg.sender}`}>
            <div className="message-icon">{msg.icon}</div>
            <div className="message-content">
              <div className="message-text">{msg.text}</div>
              <div className="message-time">
                <Clock size={10} />
                {msg.timestamp}
              </div>
            </div>
          </div>
        ))}
        
        {isTyping && (
          <div className="message-bubble bot typing">
            <div className="message-icon">🤖</div>
            <div className="message-content">
              <div className="typing-indicator">
                <span></span>
                <span></span>
                <span></span>
              </div>
            </div>
          </div>
        )}
        
        <div ref={messagesEndRef} />
      </div>

      {/* Quick Suggestions */}
      <div className="quick-suggestions">
        <div className="suggestions-header">
          <Sparkles size={16} />
          <span>Quick Questions</span>
        </div>
        <div className="suggestions-grid">
          {suggestions.map((suggestion, index) => (
            <button
              key={index}
              className="suggestion-btn"
              onClick={() => handleQuickQuestion(suggestion.text)}
              disabled={isLoading}
            >
              <span className="suggestion-icon">{suggestion.icon}</span>
              <span className="suggestion-text">{suggestion.text}</span>
              <ChevronRight size={14} />
            </button>
          ))}
        </div>
      </div>

      {/* Input Area */}
      <div className="input-container">
        <div className="input-wrapper">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={handleKeyPress}
            placeholder="Ask about fees, attendance, grades, timetable..."
            className="chat-input"
            disabled={isLoading}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className="send-btn"
          >
            {isLoading ? (
              <Loader2 size={18} className="spin" />
            ) : (
              <Send size={18} />
            )}
          </button>
        </div>
        <div className="input-hint">
          Press Enter to send • Shift+Enter for new line
        </div>
      </div>
    </div>
  );
};

export default ERPChatBot;
